import { FirewallContext, PolicyDecision } from "../../types";
import { SecretDetectionService } from "../secrets/SecretDetectionService";
import { PolicyEngine } from "../policies/PolicyEngine";

export class AiPromptFirewall {
  private readonly detection = new SecretDetectionService();

  constructor(private readonly policyEngine: PolicyEngine) {}

  inspect(context: FirewallContext): PolicyDecision {
    const { text, source } = context;

    if (source !== "clipboard" && source !== "ai") {
      return {
        allowed: true,
        reason: "Firewall only evaluates AI and clipboard traffic.",
        risk: 0,
      };
    }

    const result = this.detection.detect(text);
    if (result.findings.length === 0) {
      return {
        allowed: true,
        reason: "No risky secrets detected before transmission.",
        risk: 0,
      };
    }

    const decision = this.policyEngine.evaluate(result.findings);
    if (!decision.allowed) {
      decision.reason = `AI Prompt Firewall blocked transmission due to ${decision.reason}`;
    }

    return decision;
  }
}

import { SecretClassifier } from "./SecretClassifier";
import { SecretFinding, DetectionResult } from "../../types";

const REGEX_RULES: Array<{ name: string; pattern: RegExp; category: string }> = [
  { name: "openai", pattern: /sk-[A-Za-z0-9]{10,}/, category: "openai" },
  { name: "aws", pattern: /AKIA[0-9A-Z]{16}/, category: "aws" },
  { name: "github", pattern: /ghp_[A-Za-z0-9]{36}/, category: "github" },
  { name: "jwt", pattern: /[A-Za-z0-9-_]+\.[A-Za-z0-9-_]+\.[A-Za-z0-9-_]+/, category: "jwt" },
  { name: "ssh", pattern: /-----BEGIN (RSA|OPENSSH|DSA|EC) PRIVATE KEY-----/, category: "ssh" },
  { name: "database", pattern: /(postgres|mongodb|mysql|sqlserver).*(password|pwd|uri|connection)/i, category: "database" },
  { name: "generic", pattern: /(?:[A-Za-z0-9\-_]{20,})/, category: "generic" },
];

const CONTEXT_KEYWORDS = [
  "password",
  "secret",
  "token",
  "apikey",
  "client_secret",
  "ssh_key",
  "db_password",
  "connection_string",
];

export class SecretDetectionService {
  private classifier = new SecretClassifier();

  detect(text: string, filePath?: string): DetectionResult {
    const findings: SecretFinding[] = [];
    const seenCandidates = new Set<string>();

    for (const rule of REGEX_RULES) {
      const flags = rule.pattern.flags.includes("g")
        ? rule.pattern.flags
        : `${rule.pattern.flags}g`;
      const regex = new RegExp(rule.pattern.source, flags);
      const matches = text.matchAll(regex);
      for (const match of matches) {
        const candidate = match[0];
        if (!candidate) continue;
        const candidateKey = `${match.index ?? -1}:${candidate}`;
        if (seenCandidates.has(candidateKey)) continue;
        seenCandidates.add(candidateKey);

        const entropyScore = this.calculateEntropy(candidate);
        const contextScore = this.calculateContextScore(text, match.index ?? 0);
        const category = this.classifier.classify(candidate);
        const confidence = this.classifier.getConfidence(candidate, category);
        const risk = this.calculateRisk(entropyScore, contextScore, confidence);

        findings.push({
          value: candidate,
          category: category as any,
          location: {
            filePath,
            line: this.getLineNumber(text, match.index),
            column: this.getColumnNumber(text, match.index),
          },
          detection: {
            regexMatch: true,
            entropyScore,
            contextScore,
            confidence,
            risk,
            features: this.collectFeatures(candidate, contextScore),
          },
        });
      }
    }

    return {
      findings,
      maxRisk: findings.reduce((max, finding) => Math.max(max, finding.detection.risk), 0),
      summary: this.buildSummary(findings),
    };
  }

  private calculateEntropy(value: string): number {
    const frequency = new Map<string, number>();
    for (const character of value) {
      frequency.set(character, (frequency.get(character) ?? 0) + 1);
    }

    let entropy = 0;
    for (const count of frequency.values()) {
      const probability = count / value.length;
      entropy -= probability * Math.log2(probability);
    }

    return Number((entropy / 8).toFixed(2));
  }

  private calculateContextScore(text: string, index: number): number {
    const windowStart = Math.max(0, index - 120);
    const windowEnd = Math.min(text.length, index + 120);
    const context = text.slice(windowStart, windowEnd).toLowerCase();
    const matches = CONTEXT_KEYWORDS.filter((keyword) => context.includes(keyword));
    return Math.min(1, matches.length / 4);
  }

  private calculateRisk(entropy: number, contextScore: number, confidence: number): number {
    return Number(
      Math.min(1, entropy * 0.3 + contextScore * 0.4 + confidence * 0.3).toFixed(2)
    );
  }

  private collectFeatures(value: string, contextScore: number): string[] {
    const features = ["regex", "entropy"];
    if (contextScore > 0.3) {
      features.push("context-aware");
    }
    if (value.length > 30) {
      features.push("long-secret");
    }
    return features;
  }

  private getLineNumber(text: string, index: number | undefined): number {
    if (index === undefined || index < 0) return 0;
    return text.slice(0, index).split("\n").length;
  }

  private getColumnNumber(text: string, index: number | undefined): number {
    if (index === undefined || index < 0) return 0;
    const lines = text.slice(0, index).split("\n");
    return lines[lines.length - 1].length + 1;
  }

  private buildSummary(findings: SecretFinding[]): string {
    if (findings.length === 0) {
      return "No secrets detected.";
    }
    const byCategory = findings.reduce<Record<string, number>>((acc, item) => {
      acc[item.category] = (acc[item.category] ?? 0) + 1;
      return acc;
    }, {});
    return Object.entries(byCategory)
      .map(([category, count]) => `${count} ${category}`)
      .join(", ");
  }
}

import { SecretCategory } from "../../types";

const CATEGORY_PATTERNS: Record<SecretCategory, RegExp> = {
  openai: /sk-[A-Za-z0-9]{10,}/,
  aws: /AKIA[0-9A-Z]{16}|A3T[A-Z0-9]{16}|ACCA[0-9A-Z]{16}/,
  github: /ghp_[A-Za-z0-9]{36}|github_pat_[A-Za-z0-9_]{20,}/,
  jwt: /^[A-Za-z0-9-_]+\.[A-Za-z0-9-_]+\.[A-Za-z0-9-_]+$/,
  ssh: /-----BEGIN (RSA|OPENSSH|DSA|EC) PRIVATE KEY-----/,
  database: /(postgres|mongodb|mysql|sqlserver).*(password|pwd|uri|connection)/i,
  api_key: /api[_-]?key|apikey|client_secret/i,
  generic: /.*/,
};

export class SecretClassifier {
  classify(candidate: string): SecretCategory {
    for (const category of Object.keys(CATEGORY_PATTERNS) as SecretCategory[]) {
      if (CATEGORY_PATTERNS[category].test(candidate)) {
        return category;
      }
    }

    return "generic";
  }

  getConfidence(candidate: string, category: SecretCategory): number {
    const pattern = CATEGORY_PATTERNS[category];
    if (!pattern.test(candidate)) {
      return 0.2;
    }

    return Math.min(1, 0.5 + candidate.length / 64);
  }
}

import { PolicyDecision, PolicyRule, SecretFinding } from "../../types";

export class PolicyEngine {
  constructor(private readonly rules: PolicyRule[] = []) {}

  evaluate(findings: SecretFinding[]): PolicyDecision {
    if (this.rules.length === 0) {
      return {
        allowed: true,
        reason: "No enterprise policy configured.",
        risk: this.averageRisk(findings),
      };
    }

    const violation = this.rules.find((rule) => {
      if (!rule.enabled) return false;
      const matches = findings.filter((finding) =>
        rule.categories.includes(finding.category)
      );
      const ruleRisk = matches.reduce((score, finding) => score + finding.detection.risk, 0) / Math.max(1, matches.length);
      return ruleRisk >= rule.threshold;
    });

    if (violation) {
      return {
        allowed: false,
        reason: `Policy violation: ${violation.name} exceeded risk threshold ${violation.threshold}.`,
        ruleId: violation.id,
        risk: this.averageRisk(findings),
      };
    }

    return {
      allowed: true,
      reason: "All configured policies passed.",
      risk: this.averageRisk(findings),
    };
  }

  createRule(rule: PolicyRule): void {
    this.rules.push(rule);
  }

  getRules(): PolicyRule[] {
    return [...this.rules];
  }

  private averageRisk(findings: SecretFinding[]): number {
    if (findings.length === 0) return 0;
    return Number(
      (
        findings.reduce((sum, item) => sum + item.detection.risk, 0) / findings.length
      ).toFixed(2)
    );
  }
}

import { ClipboardAuditRecord, ClipboardAuditSummary } from "../types";

export class ClipboardAuditService {
  private readonly records: ClipboardAuditRecord[] = [];

  log(record: ClipboardAuditRecord): void {
    this.records.push(record);
  }

  getRecords(): ClipboardAuditRecord[] {
    return [...this.records];
  }

  getSummary(): ClipboardAuditSummary {
    const totalEvents = this.records.length;
    const blockedCopyAttempts = this.records.filter((record) => record.action === "blocked_copy").length;
    const decryptedPasteCount = this.records.filter((record) => record.action === "secure_paste" && record.success).length;
    const encryptedSecretsCount = this.records
      .filter((record) => record.action === "secure_copy" && record.success)
      .reduce((sum, record) => sum + record.itemCount, 0);

    return {
      totalEvents,
      blockedCopyAttempts,
      encryptedSecretsCount,
      decryptedPasteCount,
    };
  }
}

import { AiPromptFirewall } from "../core/firewall/AiPromptFirewall";
import { SecretClassifier } from "../core/secrets/SecretClassifier";
import { SecretDetectionService } from "../core/secrets/SecretDetectionService";
import { PolicyEngine } from "../core/policies/PolicyEngine";
import { SecureVault } from "../core/vault/SecureVault";
import { ClipboardAuditService } from "./ClipboardAuditService";
import { SecretCategory } from "../types";

export interface SecureCopyResult {
  text: string;
  blocked: boolean;
  reason?: string;
  risk: number;
  secretsProtected: number;
}

export class SecureCopyService {
  private readonly detection = new SecretDetectionService();
  private readonly classifier = new SecretClassifier();

  constructor(
    private readonly policyEngine: PolicyEngine,
    private readonly firewall: AiPromptFirewall,
    private readonly auditService: ClipboardAuditService,
    private readonly vault: SecureVault
  ) {}

  async copy(text: string): Promise<SecureCopyResult> {
    const detectionResult = this.detection.detect(text);
    const secretTypes = Array.from(new Set(detectionResult.findings.map((finding) => finding.category)));
    const riskScore = detectionResult.maxRisk;

    // Check policy
    const policyDecision = this.policyEngine.evaluate(detectionResult.findings);

    // Check firewall
    const firewallDecision = this.firewall.inspect({ source: "clipboard", text });

    const blocked = !policyDecision.allowed || !firewallDecision.allowed;

    if (blocked) {
      const reason = [policyDecision.reason, firewallDecision.reason].filter(Boolean).join(" ");
      this.auditService.log({
        action: "blocked_copy",
        timestamp: new Date().toISOString(),
        riskScore,
        secretTypes,
        success: false,
        reason,
        itemCount: detectionResult.findings.length,
      });
      return { text, blocked: true, reason, risk: riskScore, secretsProtected: 0 };
    }

    // Store secrets in vault, replace with tokens
    let output = text;
    let secretsProtected = 0;

    for (const finding of detectionResult.findings) {
      try {
        const classification = this.classifier.classify(finding.value) as SecretCategory;
        const vaultResult = await this.vault.store(finding.value, classification, riskScore, {
          source: "clipboard_copy",
          filePath: "clipboard",
        });

        // Replace secret with token
        output = output.replaceAll(finding.value, vaultResult.token);
        secretsProtected += 1;

        if (!secretTypes.includes(classification)) {
          secretTypes.push(classification);
        }
      } catch (error) {
        const reason = `Failed to store secret in vault: ${error instanceof Error ? error.message : String(error)}`;
        this.auditService.log({
          action: "blocked_copy",
          timestamp: new Date().toISOString(),
          riskScore,
          secretTypes,
          success: false,
          reason,
          itemCount: 1,
        });
        return { text, blocked: true, reason, risk: riskScore, secretsProtected: 0 };
      }
    }

    // Log successful copy
    this.auditService.log({
      action: "secure_copy",
      timestamp: new Date().toISOString(),
      riskScore,
      secretTypes,
      success: true,
      itemCount: secretsProtected,
    });

    return { text: output, blocked: false, risk: riskScore, secretsProtected };
  }
}

import { ClipboardAuditService } from "./ClipboardAuditService";
import { SecureVault } from "../core/vault/SecureVault";

export interface SecurePasteResult {
  text: string;
  success: boolean;
  blocked?: boolean;
  reason?: string;
  decryptedCount: number;
}

/**
 * SecurePasteService: Zero-trust secure paste with vault lookup
 *
 * Workflow:
 * 1. Extract vault reference tokens from clipboard text
 * 2. Look up each token in vault
 * 3. Validate token exists and entry is valid
 * 4. Decrypt secret using vault (master key protected)
 * 5. Replace token with original secret
 * 6. Log paste event
 *
 * Security:
 * - Token lookup fails if entry doesn't exist
 * - Decryption only succeeds with valid master key
 * - Token theft cannot recover secret
 * - Failed decryption blocks the entire paste
 */
export class SecurePasteService {
  constructor(
    private readonly auditService: ClipboardAuditService,
    private readonly vault: SecureVault
  ) {}

  async paste(text: string): Promise<SecurePasteResult> {
    const tokens = this.extractTokens(text);

    if (tokens.length === 0) {
      return { text, success: true, decryptedCount: 0 };
    }

    let decodedText = text;
    let decryptedCount = 0;
    const failedTokens: string[] = [];

    for (const token of Array.from(new Set(tokens))) {
      try {
        // Look up token in vault (master key protected)
        const result = await this.vault.retrieve(token);

        if (!result.found || !result.secret) {
          const reason = result.error || "Token not found in vault";
          failedTokens.push(`${token}: ${reason}`);
          continue;
        }

        // Replace token with decrypted secret
        decodedText = decodedText.replaceAll(token, result.secret);
        decryptedCount += 1;
      } catch (error) {
        const reason = `Token integrity validation failed: ${error instanceof Error ? error.message : String(error)}`;
        failedTokens.push(`${token}: ${reason}`);
      }
    }

    // If any tokens failed decryption, block the entire paste
    if (failedTokens.length > 0) {
      const reason = `Vault token decryption failed: ${failedTokens.join("; ")}`;
      this.auditService.log({
        action: "blocked_paste",
        timestamp: new Date().toISOString(),
        riskScore: 1,
        secretTypes: [],
        success: false,
        reason,
        itemCount: tokens.length,
      });
      return { text, success: false, blocked: true, reason, decryptedCount: 0 };
    }

    // Log successful paste
    this.auditService.log({
      action: "secure_paste",
      timestamp: new Date().toISOString(),
      riskScore: 0,
      secretTypes: [],
      success: true,
      itemCount: decryptedCount,
    });

    return { text: decodedText, success: true, decryptedCount };
  }

  /**
   * Extract vault reference tokens from text
   * Token format: DEVLEAKSHIELD_TOKEN_<uuid>
   */
  extractTokens(text: string): string[] {
    const matches = text.match(/DEVLEAKSHIELD_TOKEN_[0-9a-f]{8}-[0-9a-f]{4}-4[0-9a-f]{3}-[89ab][0-9a-f]{3}-[0-9a-f]{12}/gi);
    return matches ?? [];
  }
}

import * as vscode from "vscode";
import { CryptoService } from "../crypto/CryptoService";
import { TokenGenerator } from "../crypto/TokenGenerator";
import { VaultEntry, VaultStoreResult, VaultRetrieveResult, SecretCategory, VaultMetadata } from "../../types";

/**
 * SecureVault: Zero-trust enterprise vault architecture
 * 
 * Design:
 * - Master key stored in VS Code SecretStorage (never in plaintext files)
 * - Vault entries encrypted with master key using AES-256-GCM
 * - Tokens contain only vault reference ID (never the secret)
 * - Each entry has IV, authTag, metadata, classification, riskScore
 * - Token theft cannot recover secret without master key
 * - Vault theft cannot decrypt secrets without master key
 * 
 * Storage: VS Code SecretStorage (encrypted at rest by OS)
 * Entry format: {tokenId -> encrypted VaultEntry}
 */
export class SecureVault {
  private readonly VAULT_KEY = "devLeakShield.vault";
  private readonly VAULT_METADATA_KEY = "devLeakShield.vaultMetadata";
  private masterKey?: Buffer;
  private entries: Map<string, VaultEntry> = new Map();

  constructor(private readonly secretStorage: vscode.SecretStorage, masterKey: Buffer) {
    this.masterKey = masterKey;
  }

  /**
   * Initialize vault: Load existing entries from SecretStorage
   */
  async initialize(): Promise<void> {
    if (!this.masterKey) {
      throw new Error("Vault master key not available");
    }

    try {
      const storedData = await this.secretStorage.get(this.VAULT_KEY);
      if (!storedData) {
        // Fresh vault
        this.entries = new Map();
        await this.saveMetadata();
        return;
      }

      // Decrypt and parse vault entries
      const decrypted = CryptoService.decrypt(storedData, this.masterKey);
      const parsed = JSON.parse(decrypted) as Record<string, VaultEntry>;
      this.entries = new Map(Object.entries(parsed));
    } catch (error) {
      throw new Error(`Vault initialization failed: ${error instanceof Error ? error.message : String(error)}`);
    }
  }

  /**
   * Store secret in vault, return vault reference token
   * 
   * Flow:
   * 1. Generate unique token ID
   * 2. Encrypt secret with master key (AES-256-GCM)
   * 3. Store encrypted entry in vault
   * 4. Return token (never contains secret)
   * 
   * @param secret The plaintext secret to protect
   * @param classification Secret category (openai, aws, github, etc.)
   * @param riskScore Risk score 0.0-1.0
   * @returns VaultStoreResult with token (DEVLEAKSHIELD_TOKEN_<id>)
   */
  async store(
    secret: string,
    classification: SecretCategory,
    riskScore: number,
    metadata?: { source?: string; filePath?: string; expiresAt?: string }
  ): Promise<VaultStoreResult> {
    if (!this.masterKey) {
      throw new Error("Vault not initialized");
    }

    // Generate unique token ID
    const token = TokenGenerator.generate();
    const tokenId = TokenGenerator.extractId(token);

    // Create vault entry: encrypt secret with master key
    const entry: VaultEntry = {
      tokenId,
      encryptedSecret: CryptoService.encrypt(secret, this.masterKey),
      createdAt: new Date().toISOString(),
      classification,
      riskScore,
      metadata,
    };

    // Store in memory vault
    this.entries.set(tokenId, entry);

    // Persist to SecretStorage
    await this.persist();

    // Return token (no secret data)
    return {
      token,
      tokenId,
      classification,
      riskScore,
    };
  }

  /**
   * Retrieve secret from vault using token
   * 
   * Flow:
   * 1. Extract token ID from token
   * 2. Look up entry in vault
   * 3. Decrypt secret with master key
   * 4. Return secret only if entry exists
   * 5. Return error if token invalid or vault entry missing
   * 
   * @param token The vault reference token (DEVLEAKSHIELD_TOKEN_<id>)
   * @returns VaultRetrieveResult with secret or error
   */
  async retrieve(token: string): Promise<VaultRetrieveResult> {
    try {
      if (!TokenGenerator.isValidToken(token)) {
        return {
          found: false,
          error: "Invalid token format",
        };
      }

      const tokenId = TokenGenerator.extractId(token);
      const entry = this.entries.get(tokenId);

      if (!entry) {
        return {
          found: false,
          error: "Token not found in vault",
        };
      }

      if (!this.masterKey) {
        return {
          found: false,
          error: "Vault not initialized",
        };
      }

      // Decrypt secret
      const decrypted = CryptoService.decrypt(entry.encryptedSecret, this.masterKey);

      return {
        found: true,
        secret: decrypted,
        classification: entry.classification,
        riskScore: entry.riskScore,
      };
    } catch (error) {
      return {
        found: false,
        error: `Decryption failed: ${error instanceof Error ? error.message : String(error)}`,
      };
    }
  }

  /**
   * Delete entry from vault
   * Useful for cleanup after paste or on command
   */
  async delete(token: string): Promise<boolean> {
    try {
      const tokenId = TokenGenerator.extractId(token);
      const deleted = this.entries.delete(tokenId);
      if (deleted) {
        await this.persist();
      }
      return deleted;
    } catch {
      return false;
    }
  }

  /**
   * Get vault statistics (no secret exposure)
   */
  getSummary(): {
    totalEntries: number;
    entriesByCategory: Record<string, number>;
    averageRiskScore: number;
  } {
    const categories: Record<string, number> = {};
    let totalRisk = 0;

    for (const entry of this.entries.values()) {
      categories[entry.classification] = (categories[entry.classification] ?? 0) + 1;
      totalRisk += entry.riskScore;
    }

    return {
      totalEntries: this.entries.size,
      entriesByCategory: categories,
      averageRiskScore: this.entries.size > 0 ? totalRisk / this.entries.size : 0,
    };
  }

  /**
   * Encrypt and persist vault to SecretStorage
   * All entries are protected by master key (AES-256-GCM)
   * @private
   */
  private async persist(): Promise<void> {
    if (!this.masterKey) {
      throw new Error("Vault not initialized");
    }

    const entriesObject = Object.fromEntries(this.entries);
    const json = JSON.stringify(entriesObject);
    const encrypted = CryptoService.encrypt(json, this.masterKey);

    await this.secretStorage.store(this.VAULT_KEY, encrypted);
    await this.saveMetadata();
  }

  /**
   * Save vault metadata (not encrypted, no sensitive data)
   * @private
   */
  private async saveMetadata(): Promise<void> {
    const metadata: VaultMetadata = {
      version: 1,
      entriesCount: this.entries.size,
      createdAt: new Date().toISOString(),
      lastModified: new Date().toISOString(),
    };
    await this.secretStorage.store(this.VAULT_METADATA_KEY, JSON.stringify(metadata));
  }
}

import * as crypto from "crypto";

const ALGORITHM = "aes-256-gcm";
const IV_LENGTH = 12;
const SALT_LENGTH = 16;
const TAG_LENGTH = 16;

export class CryptoService {
  static generateKey(): Buffer {
    return crypto.randomBytes(32);
  }

  static deriveKey(password: string, salt: Buffer): Buffer {
    return crypto.pbkdf2Sync(password, salt, 200000, 32, "sha512");
  }

  static encrypt(plainText: string, key: Buffer): string {
    const iv = crypto.randomBytes(IV_LENGTH);
    const cipher = crypto.createCipheriv(ALGORITHM, key, iv);
    const encrypted = Buffer.concat([cipher.update(plainText, "utf8"), cipher.final()]);
    const authTag = cipher.getAuthTag();
    return Buffer.concat([iv, authTag, encrypted]).toString("base64");
  }

  static decrypt(cipherText: string, key: Buffer): string {
    const data = Buffer.from(cipherText, "base64");
    const iv = data.slice(0, IV_LENGTH);
    const authTag = data.slice(IV_LENGTH, IV_LENGTH + TAG_LENGTH);
    const encrypted = data.slice(IV_LENGTH + TAG_LENGTH);
    const decipher = crypto.createDecipheriv(ALGORITHM, key, iv);
    decipher.setAuthTag(authTag);
    const decrypted = Buffer.concat([decipher.update(encrypted), decipher.final()]);
    return decrypted.toString("utf8");
  }

  static hash(input: string): string {
    return crypto.createHash("sha256").update(input, "utf8").digest("hex");
  }
}

import * as crypto from "crypto";

/**
 * TokenGenerator: Generates cryptographically secure vault references
 * Tokens contain ONLY a random ID, never the secret or encryption key
 * Token format: DEVLEAKSHIELD_TOKEN_<uuid>
 * Example: DEVLEAKSHIELD_TOKEN_8f4c9e2d-a1b2-c3d4-e5f6-7890abcdef12
 */
export class TokenGenerator {
  /**
   * Generate a unique vault reference token
   * @returns Token format: DEVLEAKSHIELD_TOKEN_<uuid>
   */
  static generate(): string {
    // Generate UUID v4
    const uuid = crypto.randomUUID();
    return `DEVLEAKSHIELD_TOKEN_${uuid}`;
  }

  /**
   * Extract token ID from full token
   * @param token Full token like "DEVLEAKSHIELD_TOKEN_8f4c9e2d"
   * @returns Just the ID part: "8f4c9e2d"
   */
  static extractId(token: string): string {
    const match = token.match(/DEVLEAKSHIELD_TOKEN_(.+)/);
    if (!match || !match[1]) {
      throw new Error("Invalid token format");
    }
    return match[1];
  }

  /**
   * Check if string is a valid vault token
   */
  static isValidToken(token: string): boolean {
    return /^DEVLEAKSHIELD_TOKEN_[0-9a-f]{8}-[0-9a-f]{4}-4[0-9a-f]{3}-[89ab][0-9a-f]{3}-[0-9a-f]{12}$/i.test(token);
  }
}

import * as vscode from "vscode";
import { CryptoService } from "../crypto/CryptoService";

/**
 * SessionManager: Single source of truth for master key management
 *
 * Design:
 * - Master key (256-bit) stored in VS Code SecretStorage
 * - Generated on first launch, persists across restarts
 * - Used to encrypt/decrypt all vault entries
 * - Never stored in plaintext files
 * - Never exposed in logs
 * - Never hardcoded
 */
export class SessionManager {
  private masterKey?: Buffer;
  private readonly MASTER_KEY_STORE_KEY = "devLeakShield.masterKey";

  constructor(private readonly secretStorage: vscode.SecretStorage) {}

  /**
   * Initialize: Load or generate master key from VS Code SecretStorage
   */
  async initialize(): Promise<void> {
    const storedKey = await this.secretStorage.get(this.MASTER_KEY_STORE_KEY);

    if (storedKey) {
      this.masterKey = Buffer.from(storedKey, "base64");
      return;
    }

    // Generate new 256-bit master key on first launch
    this.masterKey = CryptoService.generateKey();
    await this.secretStorage.store(this.MASTER_KEY_STORE_KEY, this.masterKey.toString("base64"));
  }

  /**
   * Get master key for vault operations
   * Throws if not initialized
   */
  getMasterKey(): Buffer {
    if (!this.masterKey) {
      throw new Error("SessionManager not initialized. Call initialize() first.");
    }
    return this.masterKey;
  }

  /**
   * Legacy method for backward compatibility
   */
  getKey(): Buffer {
    return this.getMasterKey();
  }
}

import { execFile } from "child_process";
import { promisify } from "util";
import { SecretDetectionService } from "../secrets/SecretDetectionService";
import { PolicyEngine } from "../policies/PolicyEngine";

const execFileAsync = promisify(execFile);

/**
 * GitSecurityScanner: Cross-platform staged file secret scanning
 *
 * Design:
 * - Scan git staged files for secrets before commit
 * - Use execFile (not execSync) for non-blocking I/O
 * - Support Windows, Linux, macOS
 * - Prevent secret commits
 * - Report findings with policy evaluation
 *
 * Workflow:
 * 1. Get staged files via `git diff --cached --name-only`
 * 2. Get content of each staged file via `git show :path`
 * 3. Detect secrets in staged content
 * 4. Evaluate against policy
 * 5. Block if secrets found above threshold
 */
export class GitSecurityScanner {
  constructor(
    private readonly policyEngine: PolicyEngine,
    private readonly secretDetectionService: SecretDetectionService,
    private readonly cwd?: string
  ) {}

  /**
   * Scan staged files for secrets
   */
  async scanStagedFiles(): Promise<{
    blocked: boolean;
    reason: string;
    secretsFound: number;
  }> {
    try {
      // Get list of staged files
      const { stdout: stagedFiles } = await execFileAsync("git", ["diff", "--cached", "--name-only"], {
        encoding: "utf8",
        cwd: this.cwd,
      });

      if (!stagedFiles.trim()) {
        return { blocked: false, reason: "No staged files", secretsFound: 0 };
      }

      const files = stagedFiles.trim().split("\n");
      let totalSecretsFound = 0;
      const blockedFiles: string[] = [];

      for (const file of files) {
        if (!file.trim()) continue;

        try {
          // Get content of staged file
          const { stdout: content } = await execFileAsync("git", ["show", `:${file}`], {
            encoding: "utf8",
            maxBuffer: 10 * 1024 * 1024, // 10MB buffer
            cwd: this.cwd,
          });

          // Detect secrets
          const result = this.secretDetectionService.detect(content, file);

          if (result.findings.length > 0) {
            totalSecretsFound += result.findings.length;

            // Evaluate against policy
            const decision = this.policyEngine.evaluate(result.findings);

            if (!decision.allowed) {
              blockedFiles.push(`${file}: ${decision.reason}`);
            }
          }
        } catch (error) {
          // Skip files that can't be read (e.g., deleted files)
          if (!(error instanceof Error) || !error.message.includes("pathspec did not match")) {
            console.error(`Error scanning file ${file}:`, error);
          }
        }
      }

      if (blockedFiles.length > 0) {
        return {
          blocked: true,
          reason: `Pre-commit scan blocked. Files with secrets: ${blockedFiles.join("; ")}`,
          secretsFound: totalSecretsFound,
        };
      }

      return {
        blocked: false,
        reason: `Pre-commit scan passed. ${totalSecretsFound} secrets detected but allowed by policy.`,
        secretsFound: totalSecretsFound,
      };
    } catch (error) {
      const message = error instanceof Error ? error.message : String(error);

      // Not a git repo or git not available
      if (message.includes("not a git repository") || message.includes("git: command not found")) {
        return {
          blocked: false,
          reason: "Git not available or not a git repository",
          secretsFound: 0,
        };
      }

      return {
        blocked: true,
        reason: `Pre-commit scan failed: ${message}`,
        secretsFound: 0,
      };
    }
  }
}
